from functools import lru_cache

# === MEMOIZATION (top-down) ===
@lru_cache(maxsize=None)
def fib_memo(n):
    if n <= 1: return n
    return fib_memo(n-1) + fib_memo(n-2)

# === TABULATION (bottom-up) ===
def fib_tab(n):
    if n <= 1: return n
    a, b = 0, 1
    for _ in range(2, n+1): a, b = b, a+b
    return b

# === 0/1 Knapsack pattern ===
def knapsack(weights, values, capacity):
    n = len(weights)
    dp = [[0] * (capacity + 1) for _ in range(n + 1)]
    for i in range(1, n + 1):
        for w in range(capacity + 1):
            dp[i][w] = dp[i-1][w]  # skip item i
            if weights[i-1] <= w:
                dp[i][w] = max(dp[i][w], dp[i-1][w - weights[i-1]] + values[i-1])
    return dp[n][capacity]

# === Longest Common Subsequence ===
def lcs(s1, s2):
    m, n = len(s1), len(s2)
    dp = [[0] * (n+1) for _ in range(m+1)]
    for i in range(1, m+1):
        for j in range(1, n+1):
            if s1[i-1] == s2[j-1]: dp[i][j] = dp[i-1][j-1] + 1
            else: dp[i][j] = max(dp[i-1][j], dp[i][j-1])
    return dp[m][n]

from collections import deque

# === BFS — shortest path in unweighted graph ===
def bfs(graph, start, target):
    queue = deque([(start, [start])])
    visited = {start}
    while queue:
        node, path = queue.popleft()
        if node == target: return path
        for neighbor in graph[node]:
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append((neighbor, path + [neighbor]))
    return None  # no path

# === DFS — iterative (avoids recursion limit) ===
def dfs(graph, start):
    visited, stack = set(), [start]
    order = []
    while stack:
        node = stack.pop()
        if node in visited: continue
        visited.add(node)
        order.append(node)
        for neighbor in graph[node]:  # push all neighbors
            if neighbor not in visited:
                stack.append(neighbor)
    return order

# === Multi-source BFS (e.g., 0-1 matrix, rotting oranges) ===
def multi_source_bfs(grid, sources):
    rows, cols = len(grid), len(grid[0])
    queue = deque(sources)  # start with ALL sources simultaneously
    dist = {s: 0 for s in sources}
    dirs = [(0,1),(0,-1),(1,0),(-1,0)]
    while queue:
        r, c = queue.popleft()
        for dr, dc in dirs:
            nr, nc = r+dr, c+dc
            if 0 <= nr < rows and 0 <= nc < cols and (nr,nc) not in dist:
                dist[(nr,nc)] = dist[(r,c)] + 1
                queue.append((nr,nc))
    return dist

# === Rolling hash (Rabin-Karp) ===
def rolling_hash_search(text: str, pattern: str) -> list[int]:
    n, m = len(text), len(pattern)
    if m > n: return []
    base, mod = 256, 10**9 + 7
    # Precompute base^(m-1) mod mod
    pow_base = pow(base, m - 1, mod)
    # Hash pattern and first window
    pat_hash = sum(ord(pattern[i]) * pow(base, m - 1 - i, mod) for i in range(m)) % mod
    win_hash = sum(ord(text[i]) * pow(base, m - 1 - i, mod) for i in range(m)) % mod
    result = []
    for i in range(n - m + 1):
        if win_hash == pat_hash:
            if text[i:i+m] == pattern:  # verify (defeat hash collision)
                result.append(i)
        if i < n - m:
            # Remove leftmost char, add next char
            win_hash = (win_hash - ord(text[i]) * pow_base) % mod
            win_hash = (win_hash * base + ord(text[i + m])) % mod
    return result

# === Suffix array (naive O(N^2 log N) for interviews) ===
def suffix_array(s: str) -> list[int]:
    n = len(s)
    return sorted(range(n), key=lambda i: s[i:])

# Longest common prefix between adjacent suffixes
def lcp_array(s: str, sa: list[int]) -> list[int]:
    n = len(s)
    rank = [0] * n
    for i, pos in enumerate(sa):
        rank[pos] = i
    k = 0
    lcp = [0] * (n - 1)
    for i in range(n):
        if rank[i] == 0:
            k = 0
            continue
        j = sa[rank[i] - 1]
        while i + k < n and j + k < n and s[i + k] == s[j + k]:
            k += 1
        lcp[rank[i] - 1] = k
        if k: k -= 1
    return lcp

# Longest repeated substring via suffix array + LCP
def longest_repeated_substring(s: str) -> str:
    sa = suffix_array(s)
    lcp = lcp_array(s, sa)
    if not lcp: return ''
    max_lcp = max(lcp)
    idx = lcp.index(max_lcp)
    return s[sa[idx]:sa[idx] + max_lcp]

# === Optimization pattern: cached recursion ===
from functools import lru_cache

@lru_cache(maxsize=None)
def edit_distance(a: str, b: str) -> int:
    if not a: return len(b)
    if not b: return len(a)
    if a[0] == b[0]:
        return edit_distance(a[1:], b[1:])
    return 1 + min(
        edit_distance(a[1:], b),      # delete
        edit_distance(a, b[1:]),      # insert
        edit_distance(a[1:], b[1:]),  # replace
    )
